import { Home, Navbar, About, Resume } from "./components";
import { Routes, Route } from "react-router-dom"
import "bootstrap/dist/css/bootstrap.min.css";
import "./components/index.css";

function App() {
  return (
    <div>
      <Navbar />
      <Routes>
        <Resume />
        <Home />
        <About />
      </Routes>
    </div>
  )
}

export default App;
